            if block.get("type") == "text":
                t = block.get("text", "").strip()
                if t:
                    parts.append(t)
        return "\n".join(parts).strip()
    return ""


def extract_tool_calls(content):
    """Extract tool_calls from a content list."""
    if not isinstance(content, list):
        return []
    tc = []
    for block in content:
        if block.get("type") == "toolCall":
            tc.append({
                "id": block.get("id", ""),
                "type": "function",
                "function": {
                    "name": block.get("name", ""),
                    "arguments": json.dumps(block.get("arguments", {}))
                }
            })
    return tc


def merge_consecutive(msgs):
    """Merge consecutive assistant messages into one (text track cleanup)."""
    merged = []
    for m in msgs:
        if m["role"] == "assistant" and merged and merged[-1]["role"] == "assistant":
            prev = merged[-1]
            if prev["content"] and m["content"]:
                prev["content"] += "\n\n" + m["content"]
            elif m["content"]:
                prev["content"] = m["content"]
        else:
            merged.append(m)
    return merged


def skip_traces_already_exported(session_id, existing_traces):
    """If traces exist and manifest has entries for this session, skip unchanged."""
    return False  # Always re-export for now; safe to overwrite


# Find all session JSONL files (exclude trajectory sub-files and resets)
session_files = sorted(glob.glob(os.path.join(SESSIONS, "*.jsonl")))
session_files = [
    f for f in session_files
    if "trajectory" not in f and not f.endswith(".jsonl.lock") and ".reset." not in f
]

manifest = []

for sp in session_files:
    fname = os.path.basename(sp).replace(".jsonl", "")

    text_msgs = []     # Track 1: user/assistant pairs, merged
    trajectory_msgs = []  # Track 2: full format with tool_calls

    with open(sp) as f:
        for line in f:
            try:
                entry = json.loads(line)
            except Exception:
                continue
            if entry.get("type") != "message":
                continue
            msg = entry.get("message", {})
            role = msg.get("role", "")
            content = msg.get("content")

            text = extract_text(content)

            if role == "toolResult":
                tool_id = msg.get("toolCallId", "")
                tool_name = msg.get("toolName", "")
                trajectory_msgs.append({
                    "role": "tool",
                    "content": text or f"[empty: {tool_name}]",
                    "tool_call_id": tool_id
                })
                continue  # skip from text track

            if not text:
                continue

            if role == "user":
                text_msgs.append({"role": "user", "content": text})
                trajectory_msgs.append({"role": "user", "content": text})

            elif role == "assistant":
                # Track 1: plain text
                text_msgs.append({"role": "assistant", "content": text})
                # Track 2: include tool_calls
                assistant_msg = {"role": "assistant", "content": text}
                tool_calls = extract_tool_calls(content)
                if tool_calls:
                    assistant_msg["tool_calls"] = tool_calls
                trajectory_msgs.append(assistant_msg)

    # Post-process text track: merge consecutive assistant messages
    text_msgs = merge_consecutive(text_msgs)

    # Split both tracks into traces (turn-bundled chunks)
    for track_name, msgs, track_dir in [
        ("text", text_msgs, "text"),
        ("trajectory", trajectory_msgs, "trajectory")
    ]:
        traces = []
        current = []
        turn_count = 0
        for m in msgs:
            current.append(m)
            if m["role"] == "user":
                turn_count += 1
            elif m["role"] == "assistant":
                turn_count += 1
                # Cut trace at >= 15 turns or end of session
                if turn_count >= 15 or m == msgs[-1]:
                    if turn_count >= 2:
                        traces.append({"messages": current})
                    current = []
                    turn_count = 0
        if len(current) >= 2:
            traces.append({"messages": current})

        out_path = os.path.join(OUTPUT, track_dir, fname + ".jsonl")
        with open(out_path, "w") as f:
            for t in traces:
                f.write(json.dumps(t, ensure_ascii=False) + "\n")

        manifest.append({
            "session_id": fname,
            "date": fname[:10] if len(fname) >= 10 else "",
            "track": track_name,
            "traces": len(traces),
            "messages": len(msgs)
        })
        print(f"  {fname} -> {track_name}: {len(traces)} traces ({len(msgs)} msgs)")


def quality_check():
    """Validate exported traces for common format errors."""
    issues = 0
    for track_dir in ["text", "trajectory"]:
        for fpath in glob.glob(os.path.join(OUTPUT, track_dir, "*.jsonl")):
            fname = os.path.basename(fpath)
            with open(fpath) as fh:
                for i, line in enumerate(fh):
                    try:
                        trace = json.loads(line)
                        msgs = trace.get("messages", [])
                        if not msgs:
                            print(f"  [WARN] {fname}:{i+1} empty trace")
                            issues += 1
                            continue
                        # Check alternating roles (no consecutive same role)
                        prev = None
                        for j, m in enumerate(msgs):
                            if m["role"] == prev:
                                print(f"  [WARN] {fname}:{i+1} consecutive {m['role']} at msg {j+1}")
                                issues += 1
                            prev = m["role"]
                    except Exception as e:
                        print(f"  [ERR] {fname}:{i+1} parse error: {e}")
                        issues += 1
    return issues


issues = quality_check()
if issues == 0:
    print("\n  ✓ No quality issues in exported traces")
else:
    print(f"\n  ⚠ Found {issues} format issue(s) — check warnings above")

# Append new manifest entries (overwrite approach: rebuild manifest)
# Collect unique session-track combos and keep latest
unique = {}
for entry in manifest:
    key = (entry["session_id"], entry["track"])
    unique[key] = entry

# Rebuild manifest with all known entries
existing = []
if os.path.exists(manifest_path):
    with open(manifest_path) as mf:
        for line in mf:
            try:
                e = json.loads(line)
                k = (e["session_id"], e["track"])
                if k not in unique:
                    existing.append(e)
            except Exception:
                pass

with open(manifest_path, "w") as f:
    for e in existing + list(unique.values()):
        f.write(json.dumps(e, ensure_ascii=False) + "\n")

print(f"\nDone. Exported {len(set(e['session_id'] for e in manifest))} sessions.")
print(f"Manifest: {manifest_path}")
"}

