{"content": "#!/usr/bin/env python3
"""Export sessions into quality-filtered, multi-track training traces.

Produces three datasets under experiment/traces/:

  sft/         Chat SFT – text only, system + user/assistant alternation.
               Compatible with EVERY fine-tuning API (OpenAI, Together, Fireworks,
               Axolotl, Unsloth, LLaMA-Factory, Pioneer, etc.)

  agentic/     Full tool-calls – assistant messages include tool_calls fields,
               tool results use role=tool. OpenAI fine-tuning format.
               Compatible with: OpenAI, Together, Fireworks, vLLM LoRA.

  distill/     SFT + reasoning – assistant messages include both "content"
               (response) and "reasoning" (internal thinking trace).
               Compatible with: Pioneer API, OpenAI o1-format, models that
               support reasoning_content / thinking fields.

Each trace is one JSONL line: {"messages": [...]}

Quality pipeline:
  1. FILTER: sessions with >= 3 tool calls AND >= 2 user turns
  2. MERGE: consecutive assistant messages (text track) / keep parallel tool calls (agentic)
  3. SYSTEM: prepend system prompt from workspace files
  4. LABEL: auto-quality based on trace metrics
  5. DIVERSITY: track task types, tools used, trajectory length
"""

import json
import os
import glob
from datetime import datetime

SESSIONS = "/Users/georgemalenclaw/.openclaw/agents/main/sessions"
OUTPUT = "/Users/georgemalenclaw/.openclaw/workspace/experiment/traces"
WORKSPACE = "/Users/georgemalenclaw/.openclaw/workspace"

TRACKS = ["sft", "agentic", "distill"]

# -- Quality thresholds --
MIN_TOOL_CALLS = 3       # At least 3 tool calls = non-trivial
MIN_USER_TURNS = 2       # At least 2 user turns = real conversation, not one-liner
MIN_TOTAL_TURNS = 4      # Minimum conversation turns

# -- System prompt assembly --
def build_system_prompt():
    """Assemble system prompt from workspace context files."""
    parts = []
    for name, required in [
        ("AGENTS.md", True),
        ("SOUL.md", True),
        ("USER.md", True),
        ("IDENTITY.md", True),
        ("TOOLS.md", False),
    ]:
        path = os.path.join(WORKSPACE, name)
        if os.path.exists(path):
            with open(path) as f:
                content = f.read().strip()
            if content:
                parts.append(f"--- {name} ---\n{content}")
        elif required:
            print(f"  [WARN] Required system file missing: {name}")
    if not parts:
        return "You are a helpful assistant."
    return "\n\n".join(parts)

SYSTEM_PROMPT = build_system_prompt()

# -- Message parsing --
def extract_text(content):
    """Extract visible text blocks, skipping thinking/toolCall blocks."""
    if isinstance(content, str):
        return content.strip()
    if isinstance(content, list):
        return "\n".join(
            block.get("text", "").strip()
            for block in content
            if block.get("type") == "text" and block.get("text", "").strip()
        ).strip()
    return ""

def extract_thinking(content):
    """Extract thinking block content."""
    if isinstance(content, list):
        for block in content:
            if block.get("type") == "thinking":
                t = block.get("thinking", "").strip()
                if t:
                    return t
    return ""

def extract_tool_calls(content):
    """Extract tool_calls from a content list."""
    if not isinstance(content, list):
        return []
    return [
        {
            "id": block.get("id", ""),
            "type": "function",
            "function": {
                "name": block.get("name", ""),
                "arguments": json.dumps(block.get("arguments", {}), ensure_ascii=False)
            }
        }
        for block in content
        if block.get("type") == "toolCall"
    ]

def merge_consecutive_assistant(msgs):
    """Merge consecutive assistant messages (for SFT and distill tracks)."""
    merged = []
    for m in msgs:
        if m["role"] == "assistant" and merged and merged[-1]["role"] == "assistant":
            prev = merged[-1]
            if prev.get("content") and m.get("content"):
                prev["content"] += "\n\n" + m["content"]
            elif m.get("content"):
                prev["content"] = m["content"]
            # Merge reasoning if present (distill track)
            if m.get("reasoning") and prev.get("content"):
                # Don't merge reasoning from merged messages - it belongs to original turns
                pass
        else:
            merged.append(dict(m))
    return merged

def prepend_system(msgs, system_text):
    """Prepend system message if not already present."""
    if msgs and msgs[0].get("role") == "system":
        return msgs
    return [{"role": "system", "content": system_text}] + msgs

# -- Quality scoring --
def score_trace(messages, raw_stats):
    """Auto-label a trace based on observable quality signals.

    Returns: {"quality": str, "score": float, "labels": list[str]}
    """
    score = 0.0
    labels = []

    tool_calls = raw_stats.get("tool_calls", 0)
    tool_results = raw_stats.get("tool_results", 0)
    user_turns = raw_stats.get("user_turns", 0)
    assistant_turns = raw_stats.get("assistant_turns", 0)
    thinking_blocks = raw_stats.get("thinking_blocks", 0)
    tool_count = raw_stats.get("unique_tools", 0)
    has_error = raw_stats.get("has_error", False) or raw_stats.get("aborted", False)
    has_recover = raw_stats.get("has_recovery", False)
    msg_count = len(messages)

    # Depth signals
    if tool_calls >= 10:
        score += 2.0
        labels.append("deep_reasoning")
    elif tool_calls >= 5:
        score += 1.0
        labels.append("moderate_reasoning")

    # Tool diversity
    if tool_count >= 5:
        score += 1.5
        labels.append("diverse_tools")
    elif tool_count >= 3:
        score += 0.5

    # User engagement (multi-turn interaction = richer context)
    if user_turns >= 5:
        score += 1.0
        labels.append("extended_dialogue")
    elif user_turns >= 3:
        score += 0.5

    # Self-correction / recovery (error + recovery = excellent learning signal)
    if has_error and has_recover:
        score += 2.0
        labels.append("self_correction")
    elif has_error:
        score += 0.5
        labels.append("failure_example")

    # Thinking depth
    if thinking_blocks >= 10:
        score += 1.5
        labels.append("deep_thinking")
    elif thinking_blocks >= 3:
        score += 0.5
    elif thinking_blocks >= 1:
        score += 0.25

    # Conversation length
    if msg_count >= 30:
        score += 1.0
        labels.append("long_trajectory")
    elif msg_count >= 15:
        score += 0.5

    # Quality label
    if score >= 6.0:
        quality = "great"
    elif score >= 3.5:
        quality = "good"
    elif score >= 1.5:
        quality = "mediocre"
    else:
        quality = "poor"

    return {"quality": quality, "score": round(score, 1), "labels": labels}

def classify_task(messages):
    """Infer task type from the trace."""
    tool_names = set()
    text_lower = ""
    for m in messages:
        c = m.get("content", "")
        if isinstance(c, str):
            text_lower += c.lower() + " "
        for tc in m.get("tool_calls", []):
            try:
                fname = tc.get("function", {}).get("name", "")
                if fname:
                    tool_names.add(fname)
            except:
                pass

    if any(t in tool_names for t in ["exec", "process"]):
        if "git" in text_lower:
            return "devops"
        if "python" in text_lower or "script" in text_lower:
            return "coding"
        return "system_admin"
    if any(t in tool_names for t in ["web_search", "web_fetch"]):
        return "research"
    if any(t in tool_names for t in ["write", "edit", "read"]):
        if "git" in text_lower or "commit" in text_lower or "push" in text_lower:
            return "devops"
        return "writing"
    if any(t in tool_names for t in ["sessions_list", "sessions_history", "sessions_send"]):
        return "workflow"
    if any(t in tool_names for t in ["memory_search", "memory_get"]):
        return "memory_reasoning"
    if any(t in tool_names for t in ["image", "image_generate"]):
        return "multimedia"
    if any(t in tool_names for t in ["cron"]):
        return "automation"
    if any(t in tool_names for t in ["skill_workshop"]):
        return "skill_development"
    return "assistant"

def detect_recovery(messages):
    """Check if the trace shows error recovery (error + successful retry)."""
    has_error = False
    for m in messages:
        if m.get("role") == "tool":
            c = m.get("content", "").lower()
            if "error" in c or "failed" in c or "no such file" in c or "command not found" in c:
                has_error = True
            elif has_error and ("success" in c or "wrote" in c or "completed" in c):
                return True
        if m.get("role") == "assistant":
            c = m.get("content", "").lower()
            if "let me try" in c or "let me retry" in c or "let me fix" in c or "try again" in c:
                if has_error:
                    return True
    return False

# -- Session parsing --
def parse_session(filepath):
    """Parse a session JSONL file into raw messages + stats."""
    messages = []       # Full OpenClaw message dicts
    all_text_msgs = []  # Text-only (user + assistant)
    all_traj_msgs = []  # Full format (user + assistant with tool_calls + tool results)

    stats = {
        "tool_calls": 0,
        "tool_results": 0,
        "user_turns": 0,
        "assistant_turns": 0,
        "thinking_blocks": 0,
        "unique_tools": set(),
        "has_error": False,
        "aborted": False,
        "has_recovery": False,
        "first_ts": None,
        "last_ts": None,
    }

    with open(filepath) as f:
        for line in f:
            try:
                entry = json.loads(line)
            except:
                continue

            # Track custom events (aborts, errors)
            if entry.get("type") == "custom":
                custom = entry.get("customType", "")
                if "prompt-error" in custom or "aborted" in custom:
                    stats["aborted"] = True

            if entry.get("type") != "message":
                continue

            msg = entry.get("message", {})
            role = msg.get("role", "")
            content = msg.get("content")
            ts = msg.get("timestamp")
            usage = msg.get("usage", {})

            if stats["first_ts"] is None and ts:
                stats["first_ts"] = ts
            if ts:
                stats["last_ts"] = ts

            text = extract_text(content)

            # Tool results
            if role == "toolResult":
                stats["tool_results"] += 1
                tool_id = msg.get("toolCallId", "")
                tool_name = msg.get("toolName", "")

                if isinstance(content, list):
                    error_block = next((b for b in content if b.get("type") == "text" and 
                                       ("error" in b.get("text", "").lower() or 
                                        "failed" in b.get("text", "").lower())), None)
                    if error_block:
                        stats["has_error"] = True

                all_traj_msgs.append({
                    "role": "tool",
                    "content": text or f"[empty: {tool_name}]",
                    "tool_call_id": tool_id
                })
                continue

            if not text:
                # Skip empty messages (e.g., pure thinking blocks for text track)
                thinking = extract_thinking(content)
                if thinking:
                    stats["thinking_blocks"] += 1
                # Still create assistant entry with thinking for distill/trajectory
                if role == "assistant":
                    all_traj_msgs.append({
                        "role": "assistant",
                        "content": "",
                        "thinking": thinking  # Keep thinking for distill track
                    })
                continue

            if role == "user":
                stats["user_turns"] += 1
                all_text_msgs.append({"role": "user", "content": text})
                all_traj_msgs.append({"role": "user", "content": text})

            elif role == "assistant":
                stats["assistant_turns"] += 1

                # Text track
                all_text_msgs.append({"role": "assistant", "content": text})

                # Trajectory track
                tc = extract_tool_calls(content)
                if tc:
                    stats["tool_calls"] += len(tc)
                    for t in tc:
                        try:
                            name = t.get("function", {}).get("name", "")
                            if name:
                                stats["unique_tools"].add(name)
                        except:
                            pass

                traj_msg = {"role": "assistant", "content": text}
                if tc:
                    traj_msg["tool_calls"] = tc

                # Also capture thinking for distill track
                thinking = extract_thinking(content)
                if thinking:
                    stats["thinking_blocks"] += 1
                    traj_msg["thinking"] = thinking

                all_traj_msgs.append(traj_msg)

    # Detect recovery
    stats["has_recovery"] = detect_recovery(all_traj_msgs)

    return all_text_msgs, all_traj_msgs, stats

def split_into_traces(text_msgs, traj_msgs, min_turns=MIN_TOTAL_TURNS):
    """Split a session's messages into individual trace samples.

    Each trace is a complete conversation segment ending at an assistant response.
    We split on turn-count thresholds.
    """
    results_sft = []
    results_agentic = []
    results_distill = []

    sft_current = []
    traj_current = []
    distill_current = []
    turns = 0

    for text_m, traj_m in zip(text_msgs, traj_msgs):
        sft_msg = dict(text_m)
        traj_msg = dict(traj_m)

        # Distill track: copy content + add reasoning
        distill_msg = {"role": traj_m["role"], "content": traj_m.get("content", "")}
        if traj_m.get("thinking"):
            distill_msg["reasoning"] = traj_m["thinking"]
        if traj_m.get("tool_calls"):
            distill_msg["tool_calls"] = traj_m["tool_calls"]
        if traj_m.get("tool_call_id"):
            distill_msg["tool_call_id"] = traj_m.get("tool_call_id")

        sft_current.append(sft_msg)
        traj_current.append(traj_msg)
        distill_current.append(distill_msg)

        if traj_m["role"] == "user":
            turns += 1
        elif traj_m["role"] == "assistant":
            turns += 1

            # Cut if we hit the threshold or this is the last message
            is_last = (traj_m == traj_msgs[-1])
            if turns >= min_turns or is_last:
                if turns >= 2:
                    results_sft.append({"messages": prepend_system(merge_consecutive_assistant(sft_current), SYSTEM_PROMPT)})
                    results_agentic.append({"messages": prepend_system(traj_current, SYSTEM_PROMPT)})
                    results_distill.append({"messages": prepend_system(distill_current, SYSTEM_PROMPT)})

                sft_current = []
                traj_current = []
                distill_current = []
                turns = 0

    # Remaining messages
    if len(sft_current) >= 2:
        results_sft.append({"messages": prepend_system(merge_consecutive_assistant(sft_current), SYSTEM_PROMPT)})
        results_agentic.append({"messages": prepend_system(traj_current, SYSTEM_PROMPT)})
        results_distill.append({"messages": prepend_system(distill_current, SYSTEM_PROMPT)})

    return results_sft, results_agentic, results_distill

